const FavoritesView = () => {
    const [favoriteProperties, setFavoriteProperties] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    const fetchFavorites = useCallback(async () => {
        setLoading(true);
        try {
            const response = await api.get('/api/favorites');
            setFavoriteProperties(response.data.filter(Boolean)); // Filter out any null/undefined properties
        } catch (err) {
            setError('Failed to fetch your favorite properties.');
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchFavorites();
    }, [fetchFavorites]);

    if (loading) return <div className="text-center text-slate-400">Loading your favorites...</div>;
    if (error) return <div className="text-center text-red-400">{error}</div>;

    return (
        <div>
            {favoriteProperties.length === 0 ? (
                <div className="text-center p-10 bg-slate-800/50 rounded-2xl border border-slate-700">
                    <Heart className="mx-auto h-12 w-12 text-slate-500" />
